// Lazy-loads per-folder vault content chunks generated by
// scripts/buildVaultIndex.mjs. Vite's import.meta.glob produces a code-split
// chunk per folder; only the folder a user opens gets fetched.

const folderModules = import.meta.glob("../data/vault/*.generated.json");

const cache = new Map();

function safeFolderName(folder) {
  return folder.replace(/[^a-zA-Z0-9_-]/g, "_");
}

export async function loadFolderContent(folder) {
  if (!folder) return {};
  if (cache.has(folder)) return cache.get(folder);

  const safe = safeFolderName(folder);
  const key = `../data/vault/${safe}.generated.json`;
  const loader = folderModules[key];
  if (!loader) {
    console.warn(`[vault] No content chunk for folder: ${folder}`);
    return {};
  }
  const promise = loader().then((mod) => mod.default || mod);
  cache.set(folder, promise);
  return promise;
}

export async function loadNoteContent(notePath) {
  if (!notePath) return null;
  const folder = notePath.includes("/") ? notePath.split("/")[0] : "_root";
  const map = await loadFolderContent(folder);
  return map[notePath] ?? null;
}
